#!/usr/bin/env bash
set -euo pipefail

# ─── web3-destroyer E2E Test ───
# Boss-level test: deploys HardVault (inverse oracle bug + rounding mismatch)
# against a mock Uniswap V2 pair, seeds liquidity, runs agent in deep mode.
#
# Usage:
#   export NTFY_TOPIC=web3_destroyer_alertz
#   bash scripts/e2e_test.sh
# ─────────────────────────────────

RPC="http://127.0.0.1:8545"
PK="0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80"
FROM="0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266"
C="cast --rpc-url $RPC --private-key $PK"

echo "=== 1. Starting anvil ==="
anvil --silent &
PID=$!; sleep 2; trap "kill $PID 2>/dev/null" EXIT

echo "=== 2. Compiling contracts ==="
forge build contracts/HardVault.sol 2>&1 | tail -1

echo "=== 3. Deploying minimal ERC20 tokens ==="
TOKEN_A_BYTECODE=$(forge inspect contracts/HardVault.sol:HardVault bytecode | cut -c1-4 2>/dev/null || echo "0x60")
# Deploy minimal ERC20 using create2-like approach
TOKEN_A=$($C send --create $(cat <<'EOF' | tr -d '\n'

EOF
) --from $FROM --json 2>/dev/null | jq -r '.contractAddress')
TOKEN_B=$($C send --create $(cat <<'EOF' | tr -d '\n'

EOF
) --from $FROM --json 2>/dev/null | jq -r '.contractAddress')
echo "   Token A: $TOKEN_A"
echo "   Token B: $TOKEN_B"

echo "=== 4. Deploying mock Uniswap V2 pair ==="
PAIR=$($C send --create $(cat <<'EOF' | tr -d '\n'

EOF
) --from $FROM \
  --constructor-args 1000000000000000000 999000000000000000 $(echo $TOKEN_A) \
  --json 2>/dev/null | jq -r '.contractAddress')
echo "   Mock Pair: $PAIR"

echo "=== 5. Setting up reserves + initial liquidity ==="
# Set reserves: 1000 TOKEN_A : 2000 TOKEN_B (price = 2 TOKEN_B per TOKEN_A)
$C send $PAIR "setReserves(uint256,uint256,uint32)" \
  1000000000000000000000 2000000000000000000000 0 &>/dev/null || true

echo "=== 6. Deploying HardVault ==="
VAULT_BYTECODE=$(forge inspect contracts/HardVault.sol:HardVault bytecode)
VAULT=$($C send --create "$VAULT_BYTECODE" --from $FROM \
  --constructor-args "$PAIR" "$TOKEN_A" "$TOKEN_B" \
  --json | jq -r '.contractAddress')
echo "   HardVault: $VAULT"

echo "=== 7. Seeding vault with deposits ==="
# Deposit 100 TOKEN_A as collateral
$C send $TOKEN_A "approve(address,uint256)" $VAULT 100000000000000000000 &>/dev/null
$C send $VAULT "deposit(uint256)" 100000000000000000000 --from $FROM &>/dev/null
echo "   Deposited 100 TOKEN_A"

echo "=== 8. Running agent ==="
NTFY_TOPIC="${NTFY_TOPIC:-}" DRPC_URL="$RPC" \
  cargo run -- scan "$VAULT" --source-dir contracts/ --mode deep 2>&1 | tee /tmp/agent_out.txt

echo "=== 9. Results ==="
echo ""
echo "══════════════════════════════════════════════"
grep "finding(s)" /tmp/agent_out.txt 2>/dev/null || echo "   No finding count"
grep "💰" /tmp/agent_out.txt 2>/dev/null || echo "   No economic signals"
grep "DELEGATECALL\|SELFDESTRUCT\|oracle" /tmp/agent_out.txt 2>/dev/null || true
echo "══════════════════════════════════════════════"
echo "   ntfy topic: web3_destroyer_alertz"
echo "   Full log: /tmp/agent_out.txt"
